2959→nsresult nsHttpChannel::ProcessResponse(nsHttpConnectionInfo* aConnInfo) {
  2960→  uint32_t httpStatus = mResponseHead->Status();
  2961→
  2962→  LOG(("nsHttpChannel::ProcessResponse [this=%p httpStatus=%u]\n", this,
  2963→       httpStatus));
  2964→
  2965→  // Gather data on whether the transaction and page (if this is
  2966→  // the initial page load) is being loaded with SSL.
  2967→  glean::http::transaction_is_ssl
  2968→      .EnumGet(static_cast<glean::http::TransactionIsSslLabel>(
  2969→          mConnectionInfo->EndToEndSSL()))
  2970→      .Add();
  2971→  if (mLoadFlags & LOAD_INITIAL_DOCUMENT_URI) {
  2972→    glean::http::pageload_is_ssl
  2973→        .EnumGet(static_cast<glean::http::PageloadIsSslLabel>(
  2974→            mConnectionInfo->EndToEndSSL()))
  2975→        .Add();
  2976→  }
  2977→
  2978→  if (Telemetry::CanRecordPrereleaseData()) {
  2979→    // Gather data on various response status to monitor any increased frequency
  2980→    // of auth failures due to Bug 1896350
  2981→    switch (httpStatus) {
  2982→      case 200:
  2983→        mozilla::glean::networking::http_response_status_code.Get("200_ok"_ns)
  2984→            .Add(1);
  2985→        break;
  2986→      case 301:
  2987→        mozilla::glean::networking::http_response_status_code
  2988→            .Get("301_moved_permanently"_ns)
  2989→            .Add(1);
  2990→        break;
  2991→      case 302:
  2992→        mozilla::glean::networking::http_response_status_code
  2993→            .Get("302_found"_ns)
  2994→            .Add(1);
  2995→        break;
  2996→      case 304:
  2997→        mozilla::glean::networking::http_response_status_code
  2998→            .Get("304_not_modified"_ns)
  2999→            .Add(1);
  3000→        break;
  3001→      case 307:
  3002→        mozilla::glean::networking::http_response_status_code
  3003→            .Get("307_temporary_redirect"_ns)
  3004→            .Add(1);
  3005→        break;
  3006→      case 308:
  3007→        mozilla::glean::networking::http_response_status_code
  3008→            .Get("308_permanent_redirect"_ns)
  3009→            .Add(1);
  3010→        break;
  3011→      case 400:
  3012→        mozilla::glean::networking::http_response_status_code
  3013→            .Get("400_bad_request"_ns)
  3014→            .Add(1);
  3015→        break;
  3016→      case 401:
  3017→        mozilla::glean::networking::http_response_status_code
  3018→            .Get("401_unauthorized"_ns)
  3019→            .Add(1);
  3020→        break;
  3021→      case 403:
  3022→        mozilla::glean::networking::http_response_status_code
  3023→            .Get("403_forbidden"_ns)
  3024→            .Add(1);
  3025→        break;
  3026→      case 404:
  3027→        mozilla::glean::networking::http_response_status_code
  3028→            .Get("404_not_found"_ns)
  3029→            .Add(1);
  3030→        break;
  3031→      case 421:
  3032→        mozilla::glean::networking::http_response_status_code
  3033→            .Get("421_misdirected_request"_ns)
  3034→            .Add(1);
  3035→        break;
  3036→      case 425:
  3037→        mozilla::glean::networking::http_response_status_code
  3038→            .Get("425_too_early"_ns)
  3039→            .Add(1);
  3040→        break;
  3041→      case 429:
  3042→        mozilla::glean::networking::http_response_status_code
  3043→            .Get("429_too_many_requests"_ns)
  3044→            .Add(1);
  3045→        break;
  3046→      case 500:
  3047→        mozilla::glean::networking::http_response_status_code
  3048→            .Get("other_5xx"_ns)
  3049→            .Add(1);
  3050→        break;
  3051→      default:
  3052→        if (httpStatus >= 400 && httpStatus < 500) {
  3053→          mozilla::glean::networking::http_response_status_code
  3054→              .Get("other_4xx"_ns)
  3055→              .Add(1);
  3056→        } else if (httpStatus > 500) {
  3057→          mozilla::glean::networking::http_response_status_code
  3058→              .Get("other_5xx"_ns)
  3059→              .Add(1);
  3060→        } else {
  3061→          mozilla::glean::networking::http_response_status_code.Get("other"_ns)
  3062→              .Add(1);
  3063→        }
  3064→        break;
  3065→    }
  3066→  }
  3067→
  3068→  // We use GetReferringPage because mReferrerInfo may not be set at all(this is
  3069→  // especially useful in xpcshell tests, where we don't have an actual pageload
  3070→  // to get a referrer from).
  3071→  // Only allow 407 (authentication required) to continue
  3072→  if (mTransaction && mTransaction->ProxyConnectFailed() && httpStatus != 407) {
  3073→    return ProcessFailedProxyConnect(httpStatus);
  3074→  }
  3075→
  3076→  MOZ_ASSERT(!CachedContentIsValid() || mRaceCacheWithNetwork,
  3077→             "We should not be hitting the network if we have valid cached "
  3078→             "content unless we are racing the network and cache");
  3079→
  3080→  ProcessSSLInformation();
  3081→
  3082→  // notify "http-on-examine-response" observers
  3083→  gHttpHandler->OnExamineResponse(this);
  3084→
  3085→  return ContinueProcessResponse1(aConnInfo);
  3086→}
